import { Component, OnInit, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { ApiService } from '../../core/api.service';
import { Order } from '../../core/models';

/**
 * Storefront admin orders (`admin/orders`, admin). All orders newest-first with a
 * "Mark shipped" action. service_agent wires ApiService.allOrders()/setOrderStatus().
 */
@Component({
  selector: 'app-admin-orders',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './admin-orders.component.html',
  styleUrl: './admin-orders.component.css',
})
export class AdminOrdersComponent implements OnInit {
  readonly loading = signal(false);
  readonly error = signal<string | null>(null);

  // Mock orders across all users — service_agent replaces with ApiService.allOrders().
  readonly orders = signal<Order[]>([
    {
      id: 'o1002', userId: 'u-shopper', status: 'placed',
      shipName: 'Ada Lovelace', shipAddress: '123 Analytical Engine Way, London',
      totalCents: 25300, createdAt: '2026-07-11T14:20:00.000Z',
      items: [
        { id: 'oi1', orderId: 'o1002', productId: 'p1', qty: 1, unitPriceCents: 18900 },
        { id: 'oi2', orderId: 'o1002', productId: 'p2', qty: 2, unitPriceCents: 3200 },
      ],
    },
    {
      id: 'o1001', userId: 'u-shopper', status: 'shipped',
      shipName: 'Grace Hopper', shipAddress: '400 Naval Ave, Arlington',
      totalCents: 6400, createdAt: '2026-07-04T09:05:00.000Z',
      items: [{ id: 'oi3', orderId: 'o1001', productId: 'p4', qty: 1, unitPriceCents: 6400 }],
    },
    {
      id: 'o1000', userId: 'u-shopper2', status: 'placed',
      shipName: 'Alan Turing', shipAddress: '78 Bletchley Park, Milton Keynes',
      totalCents: 14500, createdAt: '2026-07-02T16:45:00.000Z',
      items: [{ id: 'oi4', orderId: 'o1000', productId: 'p3', qty: 1, unitPriceCents: 14500 }],
    },
  ]);

  constructor(private api: ApiService) {}

  ngOnInit(): void {
    this.loading.set(true);
    this.error.set(null);
    this.api.allOrders().subscribe({
      next: (orders) => {
        this.orders.set(orders);
        this.loading.set(false);
      },
      error: () => {
        this.error.set('Could not load orders.');
        this.loading.set(false);
      },
    });
  }

  markShipped(order: Order): void {
    this.orders.update((list) =>
      list.map((o) => (o.id === order.id ? { ...o, status: 'shipped' as const } : o)),
    );
    this.api.setOrderStatus(order.id, 'shipped').subscribe({ error: () => {} });
  }

  itemCount(order: Order): number {
    return order.items.reduce((sum, i) => sum + i.qty, 0);
  }

  money(cents: number): string {
    return '$' + (cents / 100).toFixed(2);
  }
}
